 518			// Queue-level decomposition depth cap: when the bead has already been split
 519			// to the configured limit, block it for operator review without invoking
 520			// the classifier or splitter (docs/triage/decomposition.md §Recursion depth cap).
 521			if runtime.PreClaimIntakeHook != nil && rcfg.MaxDecompositionDepth() > 0 {
 522				maxDepth := rcfg.MaxDecompositionDepth()
 523				depth := storeBeadDepth(ctx, w.Store, &candidate)
 524				if depth >= maxDepth {
 525					body, _ := json.Marshal(map[string]any{"depth": depth, "max": maxDepth})
 526					_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
 527						Kind:      "triage-overflow",
 528						Summary:   "depth cap exceeded",
 529						Body:      string(body),
 530						Actor:     assignee,
 531						Source:    "ddx work",
 532						CreatedAt: now().UTC(),
 533					})
 534					if lerr := addBeadLabel(ctx, w.Store, candidate.ID, "needs-human-decomposition"); lerr != nil && runtime.Log != nil {
 535						_, _ = fmt.Fprintf(runtime.Log, "triage-overflow label error: %v\n", lerr)
 536					}
